#!/usr/bin/env node
// MIPS32 (o32, little-endian) userspace interpreter for doomgeneric_mips.
// Runs the ELF, services its Linux-style syscalls, and lets it render/save frames.
'use strict';
const fs = require('fs');
const path = require('path');

const ELF_PATH = process.argv[2] || path.join(__dirname, 'doomgeneric_mips');

// ---------------------------------------------------------------------------
// Paged memory (64 KiB pages, lazily allocated & zero-filled)
// ---------------------------------------------------------------------------
const PAGE_SIZE = 0x10000;
const pages = new Array(0x10000); // page index = addr >>> 16

function page(addr) {
  const i = addr >>> 16;
  let p = pages[i];
  if (p === undefined) { p = new Uint8Array(PAGE_SIZE); pages[i] = p; }
  return p;
}
function r8(a) { return page(a)[a & 0xFFFF]; }
function w8(a, v) { page(a)[a & 0xFFFF] = v; }
function r16(a) { const p = page(a), o = a & 0xFFFF; return p[o] | (p[o + 1] << 8); }
function w16(a, v) { const p = page(a), o = a & 0xFFFF; p[o] = v; p[o + 1] = v >>> 8; }
function r32(a) {
  const p = page(a), o = a & 0xFFFF;
  return (p[o] | (p[o + 1] << 8) | (p[o + 2] << 16) | (p[o + 3] << 24)) >>> 0;
}
function w32(a, v) {
  const p = page(a), o = a & 0xFFFF;
  p[o] = v; p[o + 1] = v >>> 8; p[o + 2] = v >>> 16; p[o + 3] = v >>> 24;
}

function memWriteBytes(addr, buf, len) {
  for (let i = 0; i < len; i++) w8(addr + i, buf[i]);
}
function memReadBytes(addr, len) {
  const b = Buffer.allocUnsafe(len);
  for (let i = 0; i < len; i++) b[i] = r8(addr + i);
  return b;
}
function readCString(addr) {
  let s = '';
  for (;;) {
    const c = r8(addr++);
    if (c === 0) break;
    s += String.fromCharCode(c);
  }
  return s;
}

